import React, {useState, useEffect, useRef} from 'react';
import './ChatComponent.css';

const ChatComponent = () => {
    const [message, setMessage] = useState('');
    const [messages, setMessages] = useState([]);
    const [isConnected, setIsConnected] = useState(false);
    const ws = useRef(null);

    // WebSocket连接
    useEffect(() => {
        // WebSocket服务器地址 - 根据你的Python服务器修改
        const wsUrl = 'ws://localhost:8765';

        try {
            ws.current = new WebSocket(wsUrl);

            // 实际上发生了：
            // 1. 浏览器底层（C++实现）创建了真正的网络连接
            // 2. 这个网络连接运行在单独的线程中（浏览器管理）
            // 3. JavaScript主线程只是获得了对这个连接的引用
            ws.current.onopen = () => {
                console.log('WebSocket连接成功');
                setIsConnected(true);
                addSystemMessage('已连接到聊天服务器');
            };

            ws.current.onclose = () => {
                console.log('WebSocket连接关闭');
                setIsConnected(false);
                addSystemMessage('连接已断开');
            };

            ws.current.onerror = (error) => {
                console.error('WebSocket错误:', error);
                setIsConnected(false);
                addSystemMessage('连接发生错误');
            };

            // 接收消息
            // 这些事件监听器是回调函数，不是阻塞操作
            ws.current.onmessage = (event) => {
                receive(event.data);// 当消息到达时，浏览器会调用这个函数
            };

            // 执行流程：
            // 主线程 → 注册回调 → 继续执行后续代码 → 事件循环等待
            // ↓
            // 当WebSocket消息到达时 → 浏览器将回调放入事件队列 → 主线程在空闲时执行回调

        } catch (error) {
            console.error('创建WebSocket连接失败:', error);
        }

        // 清理函数
        return () => {
            if (ws.current) {
                ws.current.close();
            }
        };
    }, []);

    // 添加系统消息
    const addSystemMessage = (text) => {
        const systemMessage = {
            id: Date.now(),
            text,
            type: 'system',
            timestamp: new Date().toLocaleTimeString()
        };
        setMessages(prev => [...prev, systemMessage]);
    };

    // 接收消息
    const receive = (data) => {
        try {
            // 假设服务器发送的是JSON格式的消息
            const messageData = typeof data === 'string' ? JSON.parse(data) : data;

            const newMessage = {
                id: Date.now(),
                text: messageData.text || messageData.message || data,
                type: messageData.type || 'user',
                username: messageData.username || '其他用户',
                timestamp: new Date().toLocaleTimeString()
            };

            setMessages(prev => [...prev, newMessage]);
        } catch (error) {
            console.error('解析消息失败:', error);
            // 如果解析失败，直接显示原始数据
            const newMessage = {
                id: Date.now(),
                text: data,
                type: 'user',
                username: '其他用户',
                timestamp: new Date().toLocaleTimeString()
            };
            setMessages(prev => [...prev, newMessage]);
        }
    };

    // 发送消息
    const send = () => {
        if (!message.trim()) return;

        if (!isConnected || !ws.current || ws.current.readyState !== WebSocket.OPEN) {
            addSystemMessage('无法发送消息：连接未就绪');
            return;
        }

        try {
            // 发送消息到WebSocket服务器
            const messageData = {
                text: message,
                type: 'message',
                timestamp: new Date().toISOString()
            };

            ws.current.send(JSON.stringify(messageData));

            // 添加到本地消息列表
            const myMessage = {
                id: Date.now(),
                text: message,
                type: 'own',
                username: '我',
                timestamp: new Date().toLocaleTimeString()
            };

            setMessages(prev => [...prev, myMessage]);
            setMessage(''); // 清空输入框

        } catch (error) {
            console.error('发送消息失败:', error);
            addSystemMessage('发送消息失败');
        }
    };

    // 处理回车键发送
    const handleKeyPress = (e) => {
        if (e.key === 'Enter' && !e.shiftKey) {
            e.preventDefault();
            send();
        }
    };

    // 滚动到最新消息
    const messagesEndRef = useRef(null);
    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({behavior: "smooth"});
    };

    useEffect(() => {
        scrollToBottom();
    }, [messages]);

    return (
        <div className="chat-container">
            <div className="chat-header">
                <h3>WebSocket 聊天室</h3>
                <div className={`connection-status ${isConnected ? 'connected' : 'disconnected'}`}>
                    {isConnected ? '已连接' : '未连接'}
                </div>
            </div>

            <div className="chat-messages">
                {messages.map((msg) => (
                    <div key={msg.id} className={`message ${msg.type}`}>
                        {msg.type === 'system' ? (
                            <div className="system-message">{msg.text}</div>
                        ) : (
                            <div className="user-message">
                                <div className="message-header">
                                    <span className="username">{msg.username}</span>
                                    <span className="timestamp">{msg.timestamp}</span>
                                </div>
                                <div className="message-content">{msg.text}</div>
                            </div>
                        )}
                    </div>
                ))}
                <div ref={messagesEndRef}/>
            </div>

            <div className="chat-input-area">
                <div className="input-group">
          <textarea
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              onKeyPress={handleKeyPress}
              placeholder="输入消息... (Enter发送，Shift+Enter换行)"
              disabled={!isConnected}
              rows={3}
          />
                    <button
                        onClick={send}
                        disabled={!message.trim() || !isConnected}
                        className="send-button"
                    >
                        发送
                    </button>
                </div>
            </div>
        </div>
    );
};

export default ChatComponent;
